// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check column header', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check column header', async function() {
    // Test name: Check column header
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/evaluation-reference-behavior | 
    await driver.get("http://localhost:4200/user/evaluation-reference-behavior");

    // 2 | setWindowSize | 1936x1056 | 
    await driver.manage().window().setRect({ width: 1936, height: 1056 });

    // 3 | click | css=.ant-table-thead .ant-table-cell:nth-child(1) | 
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)")).click();

    // 4 | click | css=.ant-table-thead .ant-table-cell:nth-child(1) | 
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)")).click();

    // 5 | doubleClick | css=.ant-table-thead .ant-table-cell:nth-child(1) | 
    {
      const element = await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }

    // 6 | click | css=.ant-table-thead .ant-table-cell:nth-child(1) | 
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)")).click();

    // 7 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(1) | 評価項目
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)")).getText() == "評価項目");

    // 8 | click | css=.ant-table-thead .ant-table-cell:nth-child(2) | 
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).click();

    // 9 | click | css=.ant-table-thead .ant-table-cell:nth-child(2) | 
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).click();

    // 10 | doubleClick | css=.ant-table-thead .ant-table-cell:nth-child(2) | 
    {
      const element = await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }

    // 11 | click | css=.ant-table-thead .ant-table-cell:nth-child(2) | 
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).click();

    // 12 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(2) | 評価ポイント
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).getText() == "評価ポイント");

    // 13 | click | css=.ant-table-thead .ant-table-cell:nth-child(3) | 
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).click();

    // 14 | click | css=.ant-table-thead .ant-table-cell:nth-child(3) | 
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).click();

    // 15 | doubleClick | css=.ant-table-thead .ant-table-cell:nth-child(3) | 
    {
      const element = await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }

    // 16 | click | css=.ant-table-thead .ant-table-cell:nth-child(3) | 
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).click();

    // 17 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(3) | 難易度
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).getText() == "難易度");
  });
});
